module binary_to_gray (
	input [4:0] obf_binary,
	output reg [4:0] gray);

	always @(*) begin
		gray[4] = obf_binary[4];
		gray[3] = obf_binary[4] ^ obf_binary[3];
		gray[2] = obf_binary[3] ^ obf_binary[2];
		gray[1] = obf_binary[2] ^ obf_binary[1];
		gray[0] = obf_binary[1] ^ obf_binary[0];
	end

endmodule
